css:
:root {
  --theme-main-bg: #1a1a1a;
  --theme-panel-bg: rgba(35, 35, 35, 0.9);
  --theme-chat-bg: rgba(20, 20, 20, 0.95);
  --theme-text-main: #b0a0a0; /* Silver */
  --theme-text-secondary: #a0a0a0;
  --theme-accent-red: #B22222;
  --theme-accent-red-darker: #8B0000;
  --theme-border: rgba(178, 34, 34, 0.5);
  --user-bubble-bg: rgba(178, 34, 34, 0.65);
  --bot-bubble-bg: rgba(30, 30, 30, 0.7);
  --bubble-text-color: var(--theme-text-main);
  --header-border-radius: 8px;
  --bubble-border-radius: 8px;
  --ui-border-radius: 6px;
   --main-font: "PingFang SC", "Microsoft YaHei", "Noto Sans SC", "WenQuanYi Micro Hei", sans-serif;
  --icon-size: 32px;
}

body {
  background-color: var(--theme-main-bg) !important;
  color: var(--theme-text-main) !important;
  font-family: var(--main-font);
}

#left-nav-panel, #right-nav-panel, #character_search_bar, #rm_print_button, #rm_button_group {
  background-color: var(--theme-panel-bg) !important;
  border: 1px solid var(--theme-border) !important;
  backdrop-filter: blur(5px);
  border-radius: var(--ui-border-radius) !important;
}

#chat {
  background-color: rgba(20, 20, 20, 0.35) !important;
}

a { color: var(--theme-accent-red) !important; }
a:hover { color: var(--theme-accent-red-darker) !important; text-decoration: underline; }

::-webkit-scrollbar { width: 4px; }
::-webkit-scrollbar-track { background: rgba(40, 40, 40, 0.5); border-radius: 4px; }
::-webkit-scrollbar-thumb { background: var(--theme-accent-red); border-radius: 4px; }
::-webkit-scrollbar-thumb:hover { background: var(--theme-accent-red-darker); }

.mes {
  display: flex;
  flex-direction: column;
  align-items: center;
  width: 100%;
  margin-bottom: 15px !important;
  background-color: transparent !important;
  border: none !important;
}

.mesAvatarWrapper {
  display: flex;
  flex-direction: column;
  align-items: flex-start;
  width: 100%;
  padding: 10px 15px;
  margin-bottom: 0px;
  position: relative;
  background-repeat: no-repeat;
  background-size: cover;
  background-position: center;
  border-radius: var(--header-border-radius) var(--header-border-radius) 0 0;
  box-shadow: 0 3px 6px rgba(0, 0, 0, 0);
  border: 1px solid var(--theme-border);
  border-bottom: none;
}

.mes[is_user='true'] .mesAvatarWrapper {
  background-image: url('https://files.catbox.moe/diwizr.jpeg');
}

.mes[is_user='false'] .mesAvatarWrapper {
  background-image: url('https://files.catbox.moe/oa6mj0.jpeg');
}

.mesAvatarWrapper .avatar {
  position: relative;
  margin-bottom: 5px;
  width: 50px;
  height: 50px;
  flex-shrink: 0;
}
.mesAvatarWrapper .avatar img {
  display: block;
  border-radius: 50%;
  border: 1px solid rgba(178, 34, 34, 0.3);
}

.mes .mesAvatarWrapper .avatar::after {
  content: "";
  position: absolute;
  top: 50%;
  left: 50%;
  width: 120%;
  height: 120%;
  transform: translate(-50%, -50%);
  background-repeat: no-repeat;
  background-position: center center;
  background-size: contain;
  pointer-events: none;
  z-index: 1;
}

.mes[is_user='true'] .mesAvatarWrapper .avatar::after {
  background-image: url('https://files.catbox.moe/2mmgi1.png');
}

.mes[is_user='false'] .mesAvatarWrapper .avatar::after {
  background-image: url('https://files.catbox.moe/9w4pze.png');
}

.mes .mesAvatarWrapper .ch_name,
.mes .mesAvatarWrapper .user_name {
  color: var(--bubble-text-color) !important;
  font-size: 0.9em !important;
  font-weight: bold;
  text-shadow: 1px 1px 3px rgba(0, 0, 0, 0.8);
  padding: 0;
  margin-bottom: 4px !important;
  width: 100%;
  text-align: left;
}

.mes .mesAvatarWrapper .mes_timer,
.mes .mesAvatarWrapper .tokenCounterDisplay {
  color: var(--theme-text-secondary) !important;
  font-size: 0.75em !important;
  text-shadow: 1px 1px 2px rgba(0, 0, 0, 0.8);
  width: auto;
  max-width: 100%;
  text-align: left !important;
  margin-left: 0 !important;
  padding-left: 0 !important;
  display: block;
  margin-top: 2px;
}

.mes_block {
  width: 98%;
  padding: 10px 15px !important;
  border: 1px solid var(--theme-border) !important;
  border-top: none !important;
  border-radius: 0 0 var(--bubble-border-radius) var(--bubble-border-radius);
  box-shadow: 0 3px 6px rgba(0, 0, 0, 0.4);
  word-wrap: break-word;
  overflow-wrap: break-word;
  word-break: break-word;
  line-height: 1.6;
  margin-top: 0;
  margin-left: auto;
  margin-right: auto;
  position: relative; /* Merged */
  overflow: hidden;   /* Merged */
}

div[is_user="true"] .mes_block {
  background-color: var(--user-bubble-bg) !important;
}

div[is_user="false"] .mes_block {
  background-color: var(--bot-bubble-bg) !important;
}

.mes_block .mes_text p, .mes_block .mes_text {
  color: var(--bubble-text-color) !important;
  margin: 0 0 5px 0;
  position: relative; /* Merged */
  z-index: 1;         /* Merged */
  background-color: transparent !important; /* Merged */
}

.mes_block .mes_text p:last-child {
  margin-bottom: 0;
}

textarea, input[type="text"], input[type="number"], select {
  background-color: rgba(30, 30, 30, 0.8) !important;
  color: var(--theme-text-main) !important;
  border: 1px solid var(--theme-border) !important;
  border-radius: var(--ui-border-radius) !important;
  padding: 8px 12px !important;
}
textarea:focus, input[type="text"]:focus, input[type="number"]:focus, select:focus {
  border-color: var(--theme-accent-red) !important;
  box-shadow: 0 0 8px var(--theme-accent-red) !important;
  outline: none !important;
}

button, .menu_button { background-image: url('https://files.catbox.moe/idjw1k.jpg') !important; /* <- 更换成这个新图片 */ background-size: cover !important; background-position: center center !important; background-repeat: no-repeat !important; color: var(--theme-text-main) !important; border: 1px solid rgba(0, 0, 0, 0.6) !important; border-radius: var(--ui-border-radius) !important; padding: 8px 15px !important; transition: all 0.2s ease; text-shadow: 1px 1px 2px rgba(0, 0, 0, 0.7); font-weight: bold; }

button:hover, .menu_button:hover {
  border-color: rgba(255, 255, 255, 0.3) !important;
  cursor: pointer;
  box-shadow: 0 0 8px rgba(255, 255, 255, 0.1);
  filter: brightness(1.15);
}

#send_button, #speech_button, #generate_button, #swipe_left, #swipe_right {
  background-color: transparent !important;
  background-image: none !important;
  color: var(--theme-accent-red) !important;
  border: none !important;
  padding: 5px !important;
  text-shadow: none;
  font-weight: normal;
}
#send_button:hover, #speech_button:hover, #generate_button:hover, #swipe_left:hover, #swipe_right:hover {
  color: var(--theme-accent-red-darker) !important;
  background-color: rgba(178, 34, 34, 0.1) !important;
  filter: none;
  box-shadow: none;
}

#leftNavDrawerIcon i, #sys-settings-button i, #advanced-formatting-button i,
#WI-SP-button i, #user-settings-button i, #logo_block img,
#extensions-settings-button i, #persona-management-button i,
#rightNavDrawerIcon i {
  display: none !important;
}
#sent_button i, #sent_button span, #sent_button svg,
#options_button i, #options_button span, #options_button svg,
#extensionsMenuButton i, #extensionsMenuButton span, #extensionsMenuButton svg {
  display: none !important;
  visibility: hidden !important;
  width: 0 !important;
  height: 0 !important;
}

#leftNavDrawerIcon::before, #sys-settings-button .drawer-icon::before, #advanced-formatting-button .drawer-icon::before, #WI-SP-button .drawer-icon::before, #user-settings-button .drawer-icon::before, #logo_block .drawer-icon::before, #extensions-settings-button .drawer-icon::before, #persona-management-button .drawer-icon::before, #rightNavDrawerIcon::before {
  content: ""; display: block; width: var(--icon-size) !important; height: var(--icon-size) !important; background-size: contain; background-repeat: no-repeat; background-position: center; margin: auto;
}
#leftNavDrawerIcon::before { background-image: url('https://files.catbox.moe/xnwlgo.png'); }
#sys-settings-button .drawer-icon::before { background-image: url('https://files.catbox.moe/n4eesx.png'); }
#advanced-formatting-button .drawer-icon::before { background-image: url('https://files.catbox.moe/5vr4hq.png'); }
#WI-SP-button .drawer-icon::before { background-image: url('https://files.catbox.moe/ft6ayn.png'); }
#user-settings-button .drawer-icon::before { background-image: url('https://files.catbox.moe/vhdzli.png'); }
#logo_block .drawer-icon::before { background-image: url('https://files.catbox.moe/94wnfc.png'); }
#extensions-settings-button .drawer-icon::before { background-image: url('https://files.catbox.moe/9zooif.png'); }
#persona-management-button .drawer-icon::before { background-image: url('https://files.catbox.moe/hjdrld.png'); }
#rightNavDrawerIcon::before { background-image: url('https://files.catbox.moe/fv350t.png'); }

.fa-bars::before,
.fa-ellipsis-v::before,
.fa-paper-plane::before,
#extensionsMenuButton::before {
  display: none !important;
  content: '' !important;
}

.fa-bars {
  background: url('https://files.catbox.moe/74atex.png') center/contain no-repeat !important;
  width: 36px !important;
  height: 36px !important;
  filter: drop-shadow(0 0 2px rgba(139, 69, 19, 0.3));
}

#extensionsMenuButton {
  background: url('https://files.catbox.moe/redaym.png') center/contain no-repeat !important;
  width: 32px !important;
  height: 32px !important;
  margin-top: 2px !important;
  display: inline-block !important;
}

.fa-paper-plane {
  background: url('https://files.catbox.moe/ykcjee.png') center/contain no-repeat !important;
  width: 38px !important;
  height: 38px !important;
  margin-left: 5px !important;
}

strong, b { color: var(--theme-accent-red); font-weight: bold;}
blockquote {
  border-left: 4px solid var(--theme-accent-red);
  color: var(--theme-text-secondary);
  background-color: rgba(40, 40, 40, 0.4);
  padding: 10px 15px; margin-left: 0;
  border-radius: 0 var(--ui-border-radius) var(--ui-border-radius) 0;
}

div.toast.toast-error {
  position: fixed !important;
  top: 70px !important;
  left: 50% !important;
  transform: translateX(-50%) !important;
  margin: 0 !important;
  z-index: 10001 !important;
  width: 350px;
  max-width: 90%;
  overflow: hidden !important;
  background-color: rgba(25, 25, 25, 0.85) !important;
  background-image: none !important;
  border: 1px solid var(--theme-border) !important;
  border-radius: var(--ui-border-radius) !important;
  box-shadow: 0 5px 15px rgba(0, 0, 0, 0.6) !important;
  padding: 0 !important;
  color: inherit;
  text-shadow: none !important;
}

div.toast.toast-error .toast-header {
  background: transparent !important;
  background-image: none !important;
  color: var(--theme-text-main) !important;
  text-shadow: 1px 1px 2px rgba(0, 0, 0, 0.9) !important;
  border: none !important;
  border-bottom: 1px solid rgba(178, 34, 34, 0.3) !important;
  padding: 0.5rem 0.75rem !important;
  border-radius: 0;
}

div.toast.toast-error .toast-message {
  background-color: transparent !important;
  background-image: url('https://files.catbox.moe/r77sw4.jpeg') !important;
  background-size: cover !important;
  background-position: center center !important;
  background-repeat: no-repeat !important;
  color: var(--theme-text-main) !important;
  text-shadow: 1px 1px 2px rgba(0, 0, 0, 0.9) !important;
  padding: 0.75rem !important;
  margin: 0 !important;
  width: 100% !important;
  box-sizing: border-box !important;
  border-radius: 0;
}

div.toast.toast-error .toast-header .close {
  color: var(--theme-text-main) !important;
  text-shadow: 1px 1px 2px rgba(0, 0, 0, 0.9) !important;
  opacity: 0.8 !important;
  font-size: 1.2rem;
  font-weight: bold;
}
div.toast.toast-error .toast-header .close:hover {
  opacity: 1 !important;
}

div.toast.toast-error .toast-header strong {
  color: inherit !important;
  font-weight: bold;
}

.mes_block::after {
  content: '';
  position: absolute;
  z-index: 0;
  bottom: 5px;
  right: 3px;
  height: 70%;
  width: auto;
  min-height: 20px;
  max-height: 450px;
  aspect-ratio: 1 / 1;
  background-size: contain;
  background-repeat: no-repeat;
  background-position: center center;
  opacity: 0.55;
  pointer-events: none;
  transition: opacity 0.3s ease;
}

div[is_user="true"] .mes_block::after {
  background-image: url('https://files.catbox.moe/4eyj58.png');
}

div[is_user="false"] .mes_block::after {
  background-image: url('https://files.catbox.moe/82pqjn.png');
}

input[type="range"] {
  -webkit-appearance: none;
  appearance: none;
  width: 98%;
  background: transparent;
  cursor: pointer;
  margin: 5px 1%;
}
input[type="range"]::-moz-focus-outer {
  border: 0;
}

input[type="range"]::-webkit-slider-runnable-track {
  width: 100%;
  height: 6px;
  background-color: var(--theme-accent-red);
  border-radius: 3px;
  border: 1px solid rgba(0, 0, 0, 0.4);
}

input[type="range"]::-moz-range-track {
  width: 100%;
  height: 6px;
  background-color: var(--theme-accent-red);
  border-radius: 3px;
  border: 1px solid rgba(0, 0, 0, 0.4);
}

input[type="range"]::-webkit-slider-thumb {
  -webkit-appearance: none;
  appearance: none;
  margin-top: -9px;
  width: 24px;
  height: 24px;
  background-color: transparent;
  background-image: url('https://files.catbox.moe/50ycfz.png');
  background-size: contain;
  background-repeat: no-repeat;
  background-position: center center;
  border: none;
  cursor: pointer;
}

input[type="range"]::-moz-range-thumb {
  width: 20px;
  height: 22px;
  background-color: transparent;
  background-image: url('https://files.catbox.moe/t8xy4b.png');
  background-size: contain;
  background-repeat: no-repeat;
  background-position: center center;
  border: none;
  border-radius: 0;
  cursor: pointer;
}

.filterByFavorites {
  width: 30px !important;
  height: 30px !important;
  padding: 0 !important;
  box-sizing: border-box !important;
  font-size: 0 !important;
  color: transparent !important;
  line-height: 30px !important;
  background-image: url('https://files.catbox.moe/50ycfz.png'), url('https://files.catbox.moe/72jb0f.jpeg') !important;
  background-color: transparent !important;
  background-repeat: no-repeat, no-repeat !important;
  background-position: center center, center center !important;
  background-size: 20px 20px, cover !important;
  border: 1px solid rgba(0, 0, 0, 0.6) !important;
  border-radius: var(--ui-border-radius) !important;
  box-shadow: none !important;
  text-shadow: none !important;
  transition: all 0.2s ease;
  cursor: pointer;
  appearance: none;
  -webkit-appearance: none;
  display: inline-block;
  vertical-align: middle;
}

.filterByFavorites:hover {
  border-color: rgba(255, 255, 255, 0.3) !important;
  box-shadow: 0 0 8px rgba(255, 255, 255, 0.1) !important;
  filter: brightness(1.15);
}
